#include <bits/stdc++.h>
using namespace std;
int n,m,a[11][16],dp[11][16],sum[11][16];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            scanf("%d",&a[i][j]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            for(int k=0;k<=j;k++)
                if(dp[i-1][j-k]+a[i][k]>=dp[i][j])
                    dp[i][j]=dp[i-1][j-k]+a[i][k],sum[i][j]=k;
    printf("%d\n",dp[n][m]);
    int tmp=m;
    stack<int> s;
    for(int i=n;i;i--)
        s.push(sum[i][tmp]),tmp-=sum[i][tmp];
    for(int i=1;i<=n;i++){
        printf("%d %d\n",i,s.top());
        s.pop();
    }
    return 0;
}
